mapper.select:
SELECT id, tenant_id, user_id, memory_type, memory_key, memory_value,
       confidence, source, expire_at, created_at, updated_at
FROM t_long_term_memory
WHERE tenant_id = #{tenantId}
  AND user_id = #{userId}
ORDER BY memory_type, confidence DESC

SELECT id, tenant_id, user_id, memory_type, memory_key, memory_value,
       confidence, source, expire_at, created_at, updated_at
FROM t_long_term_memory
WHERE tenant_id = #{tenantId}
  AND user_id = #{userId}
  AND memory_type = #{memoryType}
ORDER BY confidence DESC
